sysauto_script.script:
var sla = new GlideRecord("task_sla");

sla.addQuery("task", "20c2fce283f10310809759d0deaad3b8");
sla.query();

while (sla.next()) {

    gs.info("STEP 1 - SLA FOUND");

    var incident = new GlideRecord("x_1971597_campus_0_campus_incident");

    if (incident.get(sla.task)) {

        gs.info("STEP 2 - INCIDENT FOUND");

        if (!incident.escalated) {

            gs.info("STEP 3");

            incident.escalated = true;
            incident.priority = 2;
            incident.work_notes = "Escalated by Scheduled Script";

            incident.update();

            gs.info("STEP 4 UPDATED");

            var email = incident.opened_by.getRefRecord().email;

            if (email) {

                gs.eventQueue(
    "x_1971597_campus_0.test.event",
    incident,
    incident.number.toString(),
    email
);

                gs.info("STEP 5 EVENT FIRED");
            }
        }
    }
}
